const express = require('express');
const axios = require('axios');
const app = express();

app.use(express.json());

app.post('/webhookproxy', async (req, res) => {
    const { targetUrl, ...requestBody } = req.body;

    try {
        const responseFromTargetServer = await axios.post(targetUrl, requestBody);
        res.status(200).json(responseFromTargetServer.data);
    } catch (error) {
        res.status(500).json({
            message: 'An error occurred while proxying the request',
            error: error.message,
        });
    }
});

const SERVER_PORT = process.env.SERVER_PORT || 3000;

app.listen(SERVER_PORT, () => {
    console.log(`Server is running on port ${SERVER_PORT}`);
});